// ============================================================================
// COPYWRITING PRO - OUTPUT PARSER
// Parse la reponse OpenAI et structure le resultat
// ============================================================================

const aiResponse = $input.first().json;
let parsedContent;

// Extraire le contenu de la reponse
const rawContent = aiResponse.message?.content || aiResponse.text || aiResponse.output || '';

try {
  // Essayer de parser le JSON de la reponse
  const jsonMatch = rawContent.match(/```json\s*([\s\S]*?)\s*```/) || rawContent.match(/(\{[\s\S]*\})/);

  if (jsonMatch) {
    parsedContent = JSON.parse(jsonMatch[1] || jsonMatch[0]);
  } else {
    // Fallback: extraire le texte brut
    parsedContent = {
      headline: rawContent.split('\n')[0] || 'Headline genere',
      body: rawContent,
      cta: 'En savoir plus'
    };
  }
} catch (e) {
  parsedContent = {
    headline: 'Contenu genere',
    body: rawContent,
    cta: 'Decouvrir',
    error: e.message
  };
}

// Structure de sortie pour l'Agent Principal
return [{
  json: {
    success: true,
    tool: 'copywriting_pro',
    copy: {
      headline: parsedContent.headline || '',
      subheadline: parsedContent.subheadline || '',
      body: parsedContent.body || '',
      cta: parsedContent.cta || 'En savoir plus',
      hooks_alternatifs: parsedContent.hooks_alternatifs || []
    },
    raw_response: rawContent,
    generated_at: new Date().toISOString()
  }
}];
